member_id = #{memberId}, pay_method_type_cd = #{payMethodTypeCd}, pay_method_nm = #{payMethodNm}, pay_method_alias = #{payMethodAlias}, pay_key_no = #{payKeyNo}, main_method_yn = #{mainMethodYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE pay_method_id = #{payMethodId}
